{
  "name": "MindSparks - Your Creative Idea Vault",
  "description": "A powerful application designed for visionaries to capture and refine fleeting ideas using text, voice, and visual inputs, powered by Gemini AI for instant optimization.",
  "requestFramePermissions": [
    "camera",
    "microphone"
  ]
}

export type InputMode = 'text' | 'voice' | 'photo';

export interface Idea {
  id: string;
  timestamp: number;
  originalContent: string;
  optimizedContent?: string;
  category?: string;
  type: InputMode;
  mediaUrl?: string;
  status: 'raw' | 'optimizing' | 'refined';
}

export interface OptimizationResponse {
  refinedText: string;
  category: string;
  summary: string;
  actionItems: string[];
}

import { GoogleGenAI, Type, GenerateContentResponse } from "@google/genai";
import { OptimizationResponse } from "../types";

const API_KEY = process.env.API_KEY || '';

export class GeminiService {
  private ai: GoogleGenAI;

  constructor() {
    this.ai = new GoogleGenAI({ apiKey: API_KEY });
  }

  async optimizeIdea(
    content: string, 
    mode: 'text' | 'voice' | 'photo', 
    mimeType?: string, 
    base64Data?: string
  ): Promise<OptimizationResponse> {
    const modelName = 'gemini-3-flash-preview';

    let parts: any[] = [];

    const systemInstruction = `
      You are a world-class creative strategist. 
      Your task is to take a raw, unstructured idea (which might come from a quick text note, a messy transcript, or an image of a sketch) and transform it into a structured, professional, and actionable concept.

      Always return a JSON response with:
      1. refinedText: A clear, expanded, and polished version of the idea.
      2. category: A short label (e.g., Tech, Life, Business, Art).
      3. summary: A one-sentence hook.
      4. actionItems: 3-5 next steps to make this idea real.
    `;

    if (mode === 'text') {
      parts.push({ text: `Raw idea: ${content}` });
    } else if (mode === 'voice' && base64Data) {
      parts.push({ 
        inlineData: { mimeType: mimeType || 'audio/webm', data: base64Data },
      });
      parts.push({ text: "Listen to this audio idea and optimize it." });
    } else if (mode === 'photo' && base64Data) {
      parts.push({ 
        inlineData: { mimeType: mimeType || 'image/jpeg', data: base64Data },
      });
      parts.push({ text: "Look at this image (sketch/note) and optimize the idea found within." });
    }

    const response = await this.ai.models.generateContent({
      model: modelName,
      contents: { parts },
      config: {
        systemInstruction,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            refinedText: { type: Type.STRING },
            category: { type: Type.STRING },
            summary: { type: Type.STRING },
            actionItems: {
              type: Type.ARRAY,
              items: { type: Type.STRING }
            }
          },
          required: ["refinedText", "category", "summary", "actionItems"]
        }
      }
    });

    return JSON.parse(response.text || '{}') as OptimizationResponse;
  }
}

export const gemini = new GeminiService();

import React from 'react';

