        title="Voice Memo"
      >
        <i className={`fa-solid ${isRecording ? 'fa-stop' : 'fa-microphone'} text-2xl`}></i>
      </button>

      <button 
        onClick={() => onModeSelect('photo')}
        className="p-4 bg-emerald-600 hover:bg-emerald-500 rounded-full transition-all hover:scale-110 active:scale-95"
