import React from 'react';
import { Idea } from '../types';

interface Props {
  idea: Idea;
  onClick: (id: string) => void;
}

export const IdeaCard: React.FC<Props> = ({ idea, onClick }) => {
  const getIcon = () => {
    switch (idea.type) {
      case 'text': return 'fa-pen-to-square';
      case 'voice': return 'fa-microphone';
      case 'photo': return 'fa-camera';
    }
  };

  return (
    <div 
      onClick={() => onClick(idea.id)}
      className="p-5 glass-morphism rounded-2xl cursor-pointer hover:border-blue-400/50 transition-all group relative overflow-hidden"
    >
      <div className="flex justify-between items-start mb-3">
        <span className="px-2 py-1 text-xs font-semibold uppercase tracking-wider bg-blue-900/40 text-blue-300 rounded-md border border-blue-700/30">
          {idea.category || 'Idea'}
        </span>
        <i className={`fa-solid ${getIcon()} text-slate-500 group-hover:text-blue-400 transition-colors`}></i>
      </div>

      <h3 className="font-bold text-lg mb-2 line-clamp-2 text-slate-100 group-hover:text-white">
        {idea.originalContent || (idea.type === 'voice' ? 'Voice Memo' : 'Captured Image')}
      </h3>

      <p className="text-sm text-slate-400 line-clamp-3">
        {idea.optimizedContent || 'Optimizing your spark...'}
      </p>

      <div className="mt-4 flex items-center justify-between text-[10px] text-slate-500">
        <span>{new Date(idea.timestamp).toLocaleString()}</span>
        <span className={`flex items-center gap-1 ${idea.status === 'refined' ? 'text-emerald-400' : 'text-amber-400'}`}>
          <span className={`w-2 h-2 rounded-full ${idea.status === 'refined' ? 'bg-emerald-400' : 'bg-amber-400 animate-pulse'}`}></span>
          {idea.status}
        </span>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { HashRouter, Routes, Route, useNavigate } from 'react-router-dom';
import { Idea, InputMode } from './types';
import { gemini } from './services/geminiService';
import { CaptureButtons } from './components/CaptureButtons';
import { IdeaCard } from './components/IdeaCard';

const Home: React.FC = () => {
  const [ideas, setIdeas] = useState<Idea[]>(() => {
    const saved = localStorage.getItem('mindsparks_ideas');
    return saved ? JSON.parse(saved) : [];
  });
  const [isRecording, setIsRecording] = useState(false);
  const [showInputModal, setShowInputModal] = useState<InputMode | null>(null);
  const [inputText, setInputText] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);

  const mediaRecorder = useRef<MediaRecorder | null>(null);
  const audioChunks = useRef<Blob[]>([]);
  const navigate = useNavigate();

  useEffect(() => {
    localStorage.setItem('mindsparks_ideas', JSON.stringify(ideas));
  }, [ideas]);

  const addIdea = async (idea: Idea, file?: File | Blob) => {
    setIdeas(prev => [idea, ...prev]);
    setIsProcessing(true);

    try {
      let base64Data = '';
      let mimeType = '';

      if (file) {
        mimeType = file.type;
        base64Data = await new Promise((resolve) => {
          const reader = new FileReader();
          reader.onloadend = () => {
            const result = reader.result as string;
            resolve(result.split(',')[1]);
          };
          reader.readAsDataURL(file);
        });
      }

      const refined = await gemini.optimizeIdea(
        idea.originalContent,
        idea.type,
        mimeType,
        base64Data
      );

      setIdeas(prev => prev.map(i => i.id === idea.id ? {
        ...i,
        optimizedContent: refined.refinedText,
        category: refined.category,
        status: 'refined' as const
      } : i));
    } catch (error) {
      console.error("Optimization failed:", error);
      setIdeas(prev => prev.map(i => i.id === idea.id ? { ...i, status: 'raw' as const } : i));
    } finally {
      setIsProcessing(false);
    }
  };

  const handleCaptureMode = (mode: InputMode) => {
    if (mode === 'voice') {
      if (isRecording) {
        stopRecording();
      } else {
        startRecording();
      }
    } else if (mode === 'photo') {
      const input = document.createElement('input');
      input.type = 'file';
      input.accept = 'image/*';
      input.capture = 'environment';
      input.onchange = (e: any) => {
        const file = e.target.files[0];
        if (file) {
          const newIdea: Idea = {
            id: Date.now().toString(),
            timestamp: Date.now(),
            originalContent: "Image Capture",
            type: 'photo',
            status: 'optimizing',
            mediaUrl: URL.createObjectURL(file)
          };
          addIdea(newIdea, file);
        }
      };
      input.click();
    } else {
      setShowInputModal('text');
    }
  };

  const startRecording = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      mediaRecorder.current = new MediaRecorder(stream);
      audioChunks.current = [];

      mediaRecorder.current.ondataavailable = (event) => {
        audioChunks.current.push(event.data);
      };

      mediaRecorder.current.onstop = () => {
        const audioBlob = new Blob(audioChunks.current, { type: 'audio/webm' });
        const newIdea: Idea = {
          id: Date.now().toString(),
          timestamp: Date.now(),
          originalContent: "Voice Note",
          type: 'voice',
          status: 'optimizing',
          mediaUrl: URL.createObjectURL(audioBlob)
        };
        addIdea(newIdea, audioBlob);
      };

      mediaRecorder.current.start();
      setIsRecording(true);
    } catch (err) {
      console.error("Error accessing microphone", err);
    }
  };

  const stopRecording = () => {
    if (mediaRecorder.current) {
      mediaRecorder.current.stop();
      setIsRecording(false);
    }
  };

  const handleTextSubmit = () => {
    if (!inputText.trim()) return;
    const newIdea: Idea = {
      id: Date.now().toString(),
      timestamp: Date.now(),
      originalContent: inputText,
      type: 'text',
      status: 'optimizing'
    };
    addIdea(newIdea);
    setInputText('');
    setShowInputModal(null);
  };

  return (
    <div className="max-w-4xl mx-auto px-4 pt-12 pb-32">
      <header className="mb-12 flex items-center justify-between">
        <div>
          <h1 className="text-4xl font-black bg-gradient-to-r from-blue-400 to-indigo-400 bg-clip-text text-transparent">
            MindSparks
          </h1>
          <p className="text-slate-400 mt-2">Capture lightning in a bottle.</p>
        </div>
        <div className="flex gap-4">
          <div className="text-right">
             <div className="text-xs text-slate-500 font-bold uppercase">Total Sparks</div>
             <div className="text-2xl font-mono text-blue-400">{ideas.length}</div>
          </div>
        </div>
      </header>

      {ideas.length === 0 ? (
        <div className="flex flex-col items-center justify-center py-24 text-center">
          <div className="w-24 h-24 bg-blue-900/20 rounded-full flex items-center justify-center mb-6">
            <i className="fa-solid fa-lightbulb text-4xl text-blue-400"></i>
          </div>
          <h2 className="text-2xl font-bold text-slate-200">No sparks captured yet</h2>
          <p className="text-slate-500 mt-2 max-w-sm">
            Don't let your brilliant ideas fade away. Tap a button below to save your first spark.
          </p>
        </div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          {ideas.map(idea => (
            <IdeaCard key={idea.id} idea={idea} onClick={(id) => navigate(`/idea/${id}`)} />
          ))}
        </div>
      )}

      {/* Capture Controls */}
      <CaptureButtons onModeSelect={handleCaptureMode} isRecording={isRecording} />

      {/* Quick Text Modal */}
      {showInputModal === 'text' && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-slate-950/80 backdrop-blur-sm">
          <div className="w-full max-w-lg glass-morphism rounded-3xl p-8 shadow-2xl animate-in zoom-in duration-200">
            <div className="flex justify-between items-center mb-6">
              <h2 className="text-xl font-bold">New Spark</h2>
              <button onClick={() => setShowInputModal(null)} className="text-slate-400 hover:text-white">
                <i className="fa-solid fa-xmark"></i>
              </button>
            </div>
            <textarea
              autoFocus
              className="w-full h-40 bg-slate-800/50 border border-slate-700 rounded-2xl p-4 text-white placeholder-slate-500 focus:outline-none focus:ring-2 focus:ring-blue-500 transition-all resize-none"
              placeholder="What's on your mind? Don't worry about messy thoughts..."
              value={inputText}
              onChange={(e) => setInputText(e.target.value)}
            />
            <button 
              onClick={handleTextSubmit}
              disabled={!inputText.trim()}
              className="w-full mt-6 py-4 bg-blue-600 hover:bg-blue-500 disabled:opacity-50 disabled:cursor-not-allowed rounded-2xl font-bold transition-all"
            >
              Fuel the Spark
            </button>
          </div>
        </div>
      )}

      {/* Global Processing Indicator */}
      {isProcessing && (
        <div className="fixed top-4 right-4 bg-emerald-500/10 border border-emerald-500/20 px-4 py-2 rounded-full flex items-center gap-3 animate-pulse">
           <i className="fa-solid fa-wand-magic-sparkles text-emerald-400"></i>
           <span className="text-xs font-bold text-emerald-400 uppercase tracking-tighter">AI Optimizing...</span>
        </div>
      )}
    </div>
  );
};

const IdeaDetail: React.FC = () => {
  const navigate = useNavigate();
  const ideaId = window.location.hash.split('/').pop();
  const [idea, setIdea] = useState<Idea | null>(null);

  useEffect(() => {
    const saved = localStorage.getItem('mindsparks_ideas');
    if (saved) {
      const ideas: Idea[] = JSON.parse(saved);
      const found = ideas.find(i => i.id === ideaId);
      if (found) setIdea(found);
    }
  }, [ideaId]);

  if (!idea) return <div className="p-12 text-center">Spark not found...</div>;

  return (
    <div className="max-w-4xl mx-auto px-4 py-12">
      <button 
        onClick={() => navigate('/')}
        className="mb-8 text-slate-400 hover:text-white flex items-center gap-2 group"
      >
        <i className="fa-solid fa-arrow-left group-hover:-translate-x-1 transition-transform"></i>
        Back to Vault
      </button>

      <div className="glass-morphism rounded-3xl p-8 md:p-12 overflow-hidden relative">
        <div className="absolute top-0 right-0 w-64 h-64 bg-blue-500/10 blur-[100px] -z-10 rounded-full"></div>

        <div className="flex flex-wrap items-center gap-3 mb-8">
           <span className="px-3 py-1 bg-blue-600/20 text-blue-300 rounded-lg text-xs font-bold uppercase border border-blue-500/20">
             {idea.category || 'Idea'}
           </span>
           <span className="text-xs text-slate-500">
             Captured {new Date(idea.timestamp).toLocaleString()}
           </span>
        </div>

        <h1 className="text-3xl font-black mb-8 text-white">
          {idea.type === 'text' ? idea.originalContent : `${idea.type.charAt(0).toUpperCase() + idea.type.slice(1)} Capture`}
        </h1>

        <div className="space-y-12">
          {idea.mediaUrl && (
            <section>
              <h2 className="text-xs font-bold text-slate-500 uppercase tracking-widest mb-4">Source Material</h2>
              {idea.type === 'photo' ? (
                <img src={idea.mediaUrl} alt="Captured spark" className="w-full max-h-96 object-cover rounded-2xl border border-slate-700 shadow-xl" />
              ) : (
                <audio controls src={idea.mediaUrl} className="w-full" />
              )}
            </section>
          )}

          <section>
            <div className="flex items-center gap-3 mb-6">
              <div className="w-10 h-10 bg-emerald-500/20 rounded-xl flex items-center justify-center">
                <i className="fa-solid fa-sparkles text-emerald-400"></i>
              </div>
              <h2 className="text-xl font-bold text-white">Refined Concept</h2>
            </div>

            <div className="prose prose-invert max-w-none">
              <div className="p-6 bg-slate-800/30 rounded-2xl border border-slate-700/50 leading-relaxed text-slate-200 italic">
                {idea.optimizedContent || (idea.status === 'optimizing' ? 'Our AI is currently polishing your brilliant idea into a structured plan...' : 'No refinement available.')}
              </div>
            </div>
          </section>

          {idea.status === 'refined' && (
             <section className="grid grid-cols-1 md:grid-cols-2 gap-8">
                <div className="p-6 rounded-2xl bg-indigo-500/5 border border-indigo-500/10">
                   <h3 className="text-sm font-bold text-indigo-400 uppercase mb-4">Why it matters</h3>
                   <p className="text-slate-300">This spark has been identified as a high-potential concept in the {idea.category} domain. It bridges raw observation with professional execution.</p>
                </div>
                <div className="p-6 rounded-2xl bg-emerald-500/5 border border-emerald-500/10">
                   <h3 className="text-sm font-bold text-emerald-400 uppercase mb-4">Current Status</h3>
                   <p className="text-slate-300">Ready for project development. Use the refined concept as a basis for your next masterpiece.</p>
                </div>
             </section>
          )}
        </div>
      </div>
    </div>
  );
};

const App: React.FC = () => {
  return (
    <HashRouter>
      <Routes>
        <Route path="/" element={<Home />} />
        <Route path="/idea/:id" element={<IdeaDetail />} />
      </Routes>
    </HashRouter>
  );
};

export default App;

