import { GoogleGenAI, Type, GenerateContentResponse } from "@google/genai";
import { OptimizationResponse } from "../types";

const API_KEY = process.env.API_KEY || '';

export class GeminiService {
  private ai: GoogleGenAI;

  constructor() {
    this.ai = new GoogleGenAI({ apiKey: API_KEY });
  }

  async optimizeIdea(
    content: string, 
    mode: 'text' | 'voice' | 'photo', 
    mimeType?: string, 
    base64Data?: string
  ): Promise<OptimizationResponse> {
    const modelName = 'gemini-3-flash-preview';

    let parts: any[] = [];

    const systemInstruction = `
      You are a world-class creative strategist and transcription expert. 
      Your task is to take a raw, unstructured idea (text note, audio recording, or photo) and:
      1. TRANSCRIPTION: If the input is audio or an image containing text/sketches, provide a literal, accurate transcription of what was said or written. If the input is already text, use that.
      2. OPTIMIZATION: Transform the idea into a structured, professional, and actionable concept.

      Always return a JSON response with:
      1. transcript: (CRITICAL) For audio/photo, this is the exact text found. For text input, repeat the input.
      2. refinedText: A clear, expanded, and polished version of the idea.
      3. category: A short label (e.g., Tech, Life, Business, Art).
      4. summary: A one-sentence hook.
      5. actionItems: 3-5 next steps to make this idea real.
    `;

    if (mode === 'text') {
      parts.push({ text: `Raw idea: ${content}` });
    } else if (mode === 'voice' && base64Data) {
      parts.push({ 
        inlineData: { mimeType: mimeType || 'audio/webm', data: base64Data },
      });
      parts.push({ text: "Listen carefully, transcribe everything said, and then optimize it." });
    } else if (mode === 'photo' && base64Data) {
      parts.push({ 
        inlineData: { mimeType: mimeType || 'image/jpeg', data: base64Data },
      });
      parts.push({ text: "Look at this image, transcribe any text or explain the sketch, and then optimize the idea." });
    }

    const response = await this.ai.models.generateContent({
      model: modelName,
      contents: { parts },
      config: {
        systemInstruction,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            transcript: { type: Type.STRING },
            refinedText: { type: Type.STRING },
            category: { type: Type.STRING },
            summary: { type: Type.STRING },
            actionItems: {
              type: Type.ARRAY,
              items: { type: Type.STRING }
            }
          },
          required: ["transcript", "refinedText", "category", "summary", "actionItems"]
        }
      }
    });

    return JSON.parse(response.text || '{}') as OptimizationResponse;
  }
}

