const InterviewStudio: React.FC = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const [session, setSession] = useState<Session | null>(null);
  const [inputText, setInputText] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const chatRef = useRef<any>(null);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const saved = localStorage.getItem('mindsparks_sessions');
    if (saved) {
      const data: Session[] = JSON.parse(saved);
      const found = data.find(s => s.id === id);
      if (found) {
        setSession(found);
        if (!chatRef.current) {
          chatRef.current = gemini.createInterviewChat();
          // Send initial spark automatically
          sendToAI(found.initialSpark);
        }
      }
    }
  }, [id]);

  useEffect(() => {
    scrollRef.current?.scrollTo(0, scrollRef.current.scrollHeight);
  }, [session?.messages]);

  const sendToAI = async (text: string) => {
    if (!chatRef.current) return;
    setIsTyping(true);
    try {
      const result = await chatRef.current.sendMessage({ message: text });
      const aiResponse = result.text;

      setSession(prev => {
        if (!prev) return null;
        const newMessages: Message[] = [...prev.messages, { role: 'model', text: aiResponse }];
        const updated = { ...prev, messages: newMessages };
        updateStorage(updated);
        return updated;
      });
    } finally {
      setIsTyping(false);
    }
  };

  const handleSend = () => {
    if (!inputText.trim() || !session) return;
    const userMsg: Message = { role: 'user', text: inputText };
    const updatedMessages = [...session.messages, userMsg];
    setSession({ ...session, messages: updatedMessages });
    setInputText('');
    sendToAI(inputText);
  };

  const updateStorage = (updated: Session) => {
    const saved = localStorage.getItem('mindsparks_sessions');
    if (saved) {
      const data: Session[] = JSON.parse(saved);
      const idx = data.findIndex(s => s.id === updated.id);
      if (idx > -1) {
        data[idx] = updated;
        localStorage.setItem('mindsparks_sessions', JSON.stringify(data));
      }
    }
  };

  const finishInterview = async (type: ArtifactType) => {
    if (!session) return;
    setSession({ ...session, status: 'synthesizing' });
    try {
      const artifact = await gemini.synthesizeArtifact(session.messages, type);
      const updated: Session = {
        ...session,
        status: 'completed',
        finalArtifact: {
          ...artifact,
          type
        }
      };
      setSession(updated);
      updateStorage(updated);
      navigate(`/artifact/${session.id}`);
    } catch (e) {
      console.error(e);
      alert("Synthesis failed. Try again.");
    }
  };

  if (!session) return null;

  return (
    <div className="flex h-screen bg-slate-950 text-slate-100 overflow-hidden">
      <div className="w-1/4 border-r border-slate-800 p-8 hidden lg:block overflow-y-auto">
        <button onClick={() => navigate('/')} className="mb-12 text-slate-500 hover:text-white flex items-center gap-2">
           <i className="fa-solid fa-arrow-left"></i> Vault
        </button>
        <h2 className="text-xs font-bold text-slate-500 uppercase tracking-widest mb-6">Initial Spark</h2>
        <div className="p-4 bg-slate-900 rounded-2xl border border-slate-800 italic text-slate-400 text-sm mb-8">
          "{session.initialSpark}"
        </div>

        <h2 className="text-xs font-bold text-slate-500 uppercase tracking-widest mb-6">Outcome Goal</h2>
        <div className="space-y-3">
          {(['Article', 'Interview', 'Action Plan'] as ArtifactType[]).map(type => (
            <button 
              key={type}
              onClick={() => finishInterview(type)}
              disabled={session.status === 'synthesizing'}
              className="w-full text-left px-4 py-3 rounded-xl border border-slate-800 hover:bg-indigo-600/10 hover:border-indigo-500 transition-all text-sm font-medium disabled:opacity-50"
            >
              Finish as {type}
            </button>
          ))}
        </div>
      </div>

      <div className="flex-1 flex flex-col relative">
        <div ref={scrollRef} className="flex-1 overflow-y-auto p-8 space-y-8 pb-32">
          {session.messages.map((m, i) => (
            <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
              <div className={`max-w-[80%] p-6 rounded-3xl ${m.role === 'user' ? 'bg-indigo-600 text-white rounded-tr-none shadow-xl' : 'bg-slate-900 border border-slate-800 rounded-tl-none font-serif text-lg leading-relaxed'}`}>
                {m.text}
              </div>
            </div>
          ))}
          {isTyping && (
            <div className="flex justify-start">
              <div className="bg-slate-900 p-6 rounded-3xl rounded-tl-none border border-slate-800">
                <div className="flex gap-1">
                  <div className="w-1.5 h-1.5 bg-indigo-500 rounded-full animate-bounce" style={{animationDelay: '0ms'}}></div>
                  <div className="w-1.5 h-1.5 bg-indigo-500 rounded-full animate-bounce" style={{animationDelay: '150ms'}}></div>
                  <div className="w-1.5 h-1.5 bg-indigo-500 rounded-full animate-bounce" style={{animationDelay: '300ms'}}></div>
                </div>
              </div>
            </div>
          )}
        </div>

        <div className="absolute bottom-0 left-0 right-0 p-8 bg-gradient-to-t from-slate-950 via-slate-950 to-transparent">
          <div className="max-w-3xl mx-auto relative">
            <input 
              type="text"
              value={inputText}
              onChange={e => setInputText(e.target.value)}
              onKeyDown={e => e.key === 'Enter' && handleSend()}
              placeholder="Tell me more..."
              className="w-full bg-slate-900/50 backdrop-blur border border-slate-700 rounded-full px-8 py-5 pr-16 focus:outline-none focus:border-indigo-500 transition-all shadow-2xl"
            />
            <button 
              onClick={handleSend}
              className="absolute right-3 top-1/2 -translate-y-1/2 p-3 bg-indigo-600 rounded-full hover:bg-indigo-500 transition-all"
            >
              <i className="fa-solid fa-arrow-up text-white"></i>
            </button>
          </div>
        </div>
      </div>

      {session.status === 'synthesizing' && (
        <div className="fixed inset-0 z-[100] bg-slate-950/90 backdrop-blur-xl flex flex-col items-center justify-center text-center p-8">
           <div className="w-24 h-24 mb-8 relative">
              <div className="absolute inset-0 border-4 border-indigo-500/20 rounded-full"></div>
              <div className="absolute inset-0 border-4 border-indigo-500 border-t-transparent rounded-full animate-spin"></div>
           </div>
           <h2 className="text-3xl font-serif italic mb-4">The Muse is Writing...</h2>
           <p className="text-slate-400 max-w-md">Synthesizing your conversation into a high-depth {session.finalArtifact?.type || 'artifact'}. Please wait while we perfect the narrative.</p>
        </div>
      )}
    </div>
  );
};

