import { GoogleGenAI, Type, Chat } from "@google/genai";
import { Message, ArtifactResponse, ArtifactType } from "../types";

export class GeminiService {
  /**
   * Creates a natural conversation chat instance.
   * Following the guideline to initialize GoogleGenAI with a fresh instance to ensure the latest API key is used.
   */
  createInterviewChat(): Chat {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    return ai.chats.create({
      model: 'gemini-3-pro-preview',
      config: {
        systemInstruction: `
          You are "The Muse," a world-class investigative journalist and strategic consultant. 
          Your goal is to interview the user about their raw idea to extract depth, nuance, and potential.

          RULES:
          1. Be provocative, curious, and professional. 
          2. Ask ONLY ONE question at a time.
          3. Challenge the user's assumptions politely.
          4. If the user provides audio or images, transcribe them first and then react.
          5. Keep the momentum high.
        `,
      }
    });
  }

  /**
   * Synthesizes the interview history into a structured artifact in JSON format.
   * Uses Gemini 3 Pro for advanced reasoning and structure.
   */
  async synthesizeArtifact(
    history: Message[], 
    targetType: ArtifactType
  ): Promise<ArtifactResponse> {
    // Initialize GoogleGenAI directly before usage per guidelines.
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const prompt = `
      Based on the following interview history, generate a high-quality ${targetType}.

      History:
      ${history.map(m => `${m.role.toUpperCase()}: ${m.text}`).join('\n')}

      Return a JSON object with:
      1. title: A compelling, punchy title.
      2. content: The full-length ${targetType} (Markdown supported).
      3. summary: A one-paragraph executive summary.
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING },
            content: { type: Type.STRING },
            summary: { type: Type.STRING }
          },
          required: ["title", "content", "summary"]
        },
        thinkingConfig: { thinkingBudget: 4000 }
      }
    });

    // response.text is a getter, use it directly as a string.
    const jsonStr = response.text?.trim() || '{}';
    return JSON.parse(jsonStr) as ArtifactResponse;
  }
}

