            .map((result: any) => result[0])
            .map((result: any) => result.transcript)
            .join('');
          setInputText(transcript);
        };
        recognition.current.start();
      }

      mediaRecorder.current.ondataavailable = (event) => audioChunks.current.push(event.data);
      mediaRecorder.current.onstop = () => {
        const audioBlob = new Blob(audioChunks.current, { type: 'audio/webm' });
        const mediaUrl = URL.createObjectURL(audioBlob);
        if (transcript) handleSend(transcript, mediaUrl);
      };

      mediaRecorder.current.start();
      setIsRecording(true);
    } catch (err) {
      console.error(err);
    }
  };

  const stopVoiceInput = () => {
    if (mediaRecorder.current) mediaRecorder.current.stop();
    if (recognition.current) recognition.current.stop();
    setIsRecording(false);
  };

  const updateStorage = (updated: Session) => {
    const saved = localStorage.getItem('mindsparks_sessions');
    if (saved) {
      const data: Session[] = JSON.parse(saved);
      const idx = data.findIndex(s => s.id === updated.id);
      if (idx > -1) {
        data[idx] = updated;
        localStorage.setItem('mindsparks_sessions', JSON.stringify(data));
      }
    }
  };

  const finishInterview = async (type: ArtifactType) => {
    if (!session) return;
    setSession({ ...session, status: 'synthesizing' });
    try {
      const artifact = await gemini.synthesizeArtifact(session.messages, type);
      const updated: Session = {
        ...session,
        status: 'completed',
        finalArtifact: { ...artifact, type }
      };
      setSession(updated);
      updateStorage(updated);
      navigate(`/artifact/${session.id}`);
    } catch (e) {
      console.error(e);
      alert("Synthesis failed.");
    }
  };

  if (!session) return null;

  return (
    <div className="flex h-screen bg-slate-950 text-slate-100 overflow-hidden">
      {/* Sidebar */}
      <div className="w-1/4 border-r border-slate-800 p-8 hidden lg:block overflow-y-auto">
        <button onClick={() => navigate('/')} className="mb-12 text-slate-500 hover:text-white flex items-center gap-2">
