        </button>
        <h2 className="text-xs font-bold text-slate-500 uppercase tracking-widest mb-6">Initial Spark</h2>
        <div className="p-4 bg-slate-900 rounded-2xl border border-slate-800 italic text-slate-400 text-sm mb-8">
          "{session.initialSpark}"
        </div>

        <h2 className="text-xs font-bold text-slate-500 uppercase tracking-widest mb-6">Outcome Goal</h2>
        <div className="space-y-3">
          {(['Article', 'Interview', 'Action Plan'] as ArtifactType[]).map(type => (
            <button 
              key={type}
              onClick={() => finishInterview(type)}
              disabled={session.status === 'synthesizing'}
              className="w-full text-left px-4 py-3 rounded-xl border border-slate-800 hover:bg-indigo-600/10 hover:border-indigo-500 transition-all text-sm font-medium disabled:opacity-50"
            >
              Finish as {type}
            </button>
          ))}
        </div>
      </div>

      {/* Main Chat Area */}
      <div className="flex-1 flex flex-col relative">
        <div ref={scrollRef} className="flex-1 overflow-y-auto p-8 space-y-8 pb-32">
          {session.messages.map((m, i) => (
            <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
              <div className={`max-w-[80%] p-6 rounded-3xl ${m.role === 'user' ? 'bg-indigo-600 text-white rounded-tr-none shadow-xl' : 'bg-slate-900 border border-slate-800 rounded-tl-none font-serif text-lg leading-relaxed'}`}>
                {m.text}
                {m.mediaUrl && (
                  <div className="mt-3 pt-3 border-t border-white/20">
                    <audio src={m.mediaUrl} controls className="h-8 brightness-0 invert opacity-50 hover:opacity-100 transition-opacity" />
                  </div>
                )}
              </div>
            </div>
          ))}
          {isTyping && (
            <div className="flex justify-start animate-pulse">
              <div className="bg-slate-900 p-6 rounded-3xl rounded-tl-none border border-slate-800 text-indigo-400 font-bold italic text-sm">
                The Muse is contemplating...
              </div>
            </div>
          )}
        </div>

        {/* Input Bar */}
        <div className="absolute bottom-0 left-0 right-0 p-8 bg-gradient-to-t from-slate-950 via-slate-950 to-transparent">
          <div className="max-w-3xl mx-auto flex gap-4 items-center">
            <button 
              onClick={isRecording ? stopVoiceInput : startVoiceInput}
              className={`p-5 rounded-full shadow-2xl transition-all ${isRecording ? 'bg-red-500 animate-pulse' : 'bg-slate-800 hover:bg-slate-700'}`}
