import { GoogleGenAI, Type, Chat } from "@google/genai";
import { Message, ArtifactResponse, ArtifactType } from "../types";

export class GeminiService {
  /**
   * 创建一个具有深度采访能力的聊天实例。
   */
  createInterviewChat(): Chat {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    return ai.chats.create({
      model: 'gemini-3-pro-preview',
      config: {
        systemInstruction: `
          你是一位名为“缪斯”的世界级深度访谈记者和战略顾问。
          你的目标是通过与用户的交谈，将他们破碎、原始的想法挖掘成有深度、有逻辑、有见地的成果。

          对话规则：
          1. 始终使用中文。
          2. 表现出极强的好奇心、专业感和洞察力。
          3. 每次只提一个问题。
          4. 针对用户的回答进行追问，挑战其假设，引导其进行深层次思考。
          5. 如果用户提供的是语音转文字的内容，先肯定其核心点，再进行延伸。
          6. 你的语气应该是儒雅、敏锐且富有启发性的。
        `,
      }
    });
  }

  /**
   * 将访谈记录合成为高质量的中文成果。
   */
  async synthesizeArtifact(
    history: Message[], 
    targetType: ArtifactType
  ): Promise<ArtifactResponse> {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    // 翻译目标类型
    const typeMap = {
      'Article': '深度文章',
      'Interview': '精彩访谈录',
      'Action Plan': '行动执行方案'
    };

    const prompt = `
      基于以下访谈记录，生成一份高质量的 ${typeMap[targetType]}。

      访谈历史：
      ${history.map(m => `${m.role === 'user' ? '用户' : '缪斯'}: ${m.text}`).join('\n')}

      请返回一个 JSON 对象，包含：
      1. title: 一个具有吸引力、专业且深度的标题。
      2. content: ${typeMap[targetType]} 的正文内容，支持 Markdown 格式，要求逻辑严密、文采斐然。
      3. summary: 一段精炼的摘要，概述该想法的核心价值。

      语言必须为中文。
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING },
            content: { type: Type.STRING },
            summary: { type: Type.STRING }
          },
          required: ["title", "content", "summary"]
        },
        thinkingConfig: { thinkingBudget: 4000 }
      }
    });

    const jsonStr = response.text?.trim() || '{}';
    return JSON.parse(jsonStr) as ArtifactResponse;
  }
}

export const gemini = new GeminiService();

import React, { useState, useEffect, useRef } from 'react';
import { HashRouter, Routes, Route, useNavigate, useParams } from 'react-router-dom';
import { Session, Message, InputMode, ArtifactType } from './types';
import { gemini } from './services/geminiService';
import { CaptureButtons } from './components/CaptureButtons';
import { IdeaCard } from './components/IdeaCard';

const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;

const Home: React.FC = () => {
  const [sessions, setSessions] = useState<Session[]>(() => {
    const saved = localStorage.getItem('mindsparks_sessions');
    return saved ? JSON.parse(saved) : [];
  });
  const [isRecording, setIsRecording] = useState(false);
  const mediaRecorder = useRef<MediaRecorder | null>(null);
  const recognition = useRef<any>(null);
  const audioChunks = useRef<Blob[]>([]);
  const navigate = useNavigate();

  const startNewSession = async (mode: InputMode, initialContent: string, mediaUrl?: string) => {
    const newSession: Session = {
      id: Date.now().toString(),
      timestamp: Date.now(),
      initialSpark: initialContent,
      type: mode,
      status: 'interviewing',
      messages: [{ role: 'user', text: initialContent, mediaUrl }],
      mediaUrl: mediaUrl
    };
    const updated = [newSession, ...sessions];
    setSessions(updated);
    localStorage.setItem('mindsparks_sessions', JSON.stringify(updated));
    navigate(`/interview/${newSession.id}`);
  };

  const startRecording = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      mediaRecorder.current = new MediaRecorder(stream);
      audioChunks.current = [];

      let transcript = '';
      if (SpeechRecognition) {
        recognition.current = new SpeechRecognition();
        recognition.current.lang = 'zh-CN'; // 设置为中文识别
        recognition.current.continuous = true;
        recognition.current.interimResults = true;
        recognition.current.onresult = (event: any) => {
          transcript = Array.from(event.results)
            .map((result: any) => result[0])
            .map((result: any) => result.transcript)
            .join('');
        };
        recognition.current.start();
      }

      mediaRecorder.current.ondataavailable = (event) => audioChunks.current.push(event.data);
      mediaRecorder.current.onstop = () => {
        const audioBlob = new Blob(audioChunks.current, { type: 'audio/webm' });
        const mediaUrl = URL.createObjectURL(audioBlob);
        startNewSession('voice', transcript || "（语音已录制，但未检测到文字）", mediaUrl);
      };

      mediaRecorder.current.start();
      setIsRecording(true);
    } catch (err) {
      console.error("无法访问麦克风", err);
      alert("请允许访问麦克风以使用语音功能。");
    }
  };

  const stopRecording = () => {
    if (mediaRecorder.current) mediaRecorder.current.stop();
    if (recognition.current) recognition.current.stop();
    setIsRecording(false);
  };

  const handleCapture = (mode: InputMode) => {
    if (mode === 'text') {
       const text = prompt("现在的灵感火花是什么？");
       if (text) startNewSession('text', text);
    } else if (mode === 'photo') {
      const input = document.createElement('input');
      input.type = 'file';
      input.accept = 'image/*';
      input.onchange = (e: any) => {
        const file = e.target.files[0];
        if (file) startNewSession('photo', "已上传灵感图片", URL.createObjectURL(file));
      };
      input.click();
    } else if (mode === 'voice') {
      if (isRecording) stopRecording();
      else startRecording();
    }
  };

  return (
    <div className="max-w-5xl mx-auto px-6 py-16 min-h-screen">
      <header className="mb-16 border-b border-slate-800 pb-8">
        <h1 className="text-5xl font-serif font-black tracking-tight text-white mb-2 italic">缪斯</h1>
        <p className="text-slate-400 font-medium font-serif italic">将瞬间的火花转化为深刻的叙事。</p>
      </header>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
        {sessions.map(s => (
          <IdeaCard 
            key={s.id} 
            session={s} 
            onClick={(id) => navigate(s.status === 'completed' ? `/artifact/${id}` : `/interview/${id}`)} 
          />
        ))}
      </div>

      <CaptureButtons onModeSelect={handleCapture} isRecording={isRecording} />
    </div>
  );
};

