              onClick={isRecording ? stopVoiceInput : startVoiceInput}
              className={`p-5 rounded-full shadow-2xl transition-all ${isRecording ? 'bg-red-500 animate-pulse scale-110' : 'bg-slate-800 hover:bg-slate-700'}`}
            >
              <i className={`fa-solid ${isRecording ? 'fa-stop' : 'fa-microphone'} text-white`}></i>
            </button>
            <div className="flex-1 relative">
              <input 
                type="text"
                value={inputText}
                onChange={e => setInputText(e.target.value)}
                onKeyDown={e => e.key === 'Enter' && handleSend(inputText)}
                placeholder={isRecording ? "请说话，缪斯正在倾听..." : "继续深入交流你的想法..."}
                className="w-full bg-slate-900/50 backdrop-blur border border-slate-700 rounded-full px-8 py-5 pr-16 focus:outline-none focus:border-indigo-500 transition-all shadow-2xl text-lg"
              />
              <button 
                onClick={() => handleSend(inputText)}
                className="absolute right-3 top-1/2 -translate-y-1/2 p-3 bg-indigo-600 rounded-full hover:bg-indigo-500 transition-all"
              >
                <i className="fa-solid fa-arrow-up text-white"></i>
              </button>
            </div>
          </div>
        </div>
      </div>

      {session.status === 'synthesizing' && (
        <div className="fixed inset-0 z-[100] bg-slate-950/90 backdrop-blur-xl flex flex-col items-center justify-center text-center p-8">
           <div className="w-24 h-24 mb-8 relative">
              <div className="absolute inset-0 border-4 border-indigo-500/20 rounded-full"></div>
              <div className="absolute inset-0 border-4 border-indigo-500 border-t-transparent rounded-full animate-spin"></div>
