import { GoogleGenAI, Type, Chat } from "@google/genai";
import { Message, ArtifactResponse, ArtifactType } from "../types";

export class GeminiService {
  /**
   * 创建一个具有深度采访能力的聊天实例。
   * @param history 之前的对话历史，用于延续思考。
   */
  createInterviewChat(history: Message[] = []): Chat {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    // 将应用内的 Message 格式转换为 Gemini SDK 要求的 history 格式
    const geminiHistory = history.map(m => ({
      role: m.role === 'user' ? 'user' : 'model',
      parts: [{ text: m.text }]
    }));

    return ai.chats.create({
      model: 'gemini-3-pro-preview',
      // 如果有历史记录，则加载历史
      history: geminiHistory.length > 0 ? geminiHistory : undefined,
      config: {
        systemInstruction: `
          你是一位名为“缪斯”的世界级深度访谈记者和战略顾问。
          你的目标是通过与用户的交谈，将他们破碎、原始的想法挖掘成有深度、有逻辑、有见地的成果。

          对话规则：
          1. 始终使用中文。
          2. 表现出极强的好奇心、专业感和洞察力。
          3. 每次只提一个问题。
          4. 如果用户是在已有成果基础上“继续深度探讨”，请针对之前的结论提出更深层的挑战或新的维度。
          5. 引导用户从执行力、社会影响、未来趋势等多个角度深入思考。
          6. 你的语气应该是儒雅、敏锐且富有启发性的。
        `,
      }
    });
  }

  /**
   * 将访谈记录合成为高质量的中文成果。
   */
  async synthesizeArtifact(
    history: Message[], 
    targetType: ArtifactType
  ): Promise<ArtifactResponse> {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    const typeMap = {
      'Article': '深度文章',
      'Interview': '精彩访谈录',
      'Action Plan': '行动执行方案'
    };

    const prompt = `
      基于以下访谈记录，生成一份最新的高质量 ${typeMap[targetType]}。

      访谈历史（包含之前的多轮对话）：
      ${history.map(m => `${m.role === 'user' ? '用户' : '缪斯'}: ${m.text}`).join('\n')}

      请返回一个 JSON 对象，包含：
      1. title: 一个具有吸引力、专业且深度的标题。
      2. content: ${typeMap[targetType]} 的正文内容，支持 Markdown 格式。
      3. summary: 一段精炼的摘要，概述该想法目前进化到的核心阶段。

      语言必须为中文。
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING },
            content: { type: Type.STRING },
            summary: { type: Type.STRING }
          },
          required: ["title", "content", "summary"]
        },
        thinkingConfig: { thinkingBudget: 4000 }
      }
    });

    const jsonStr = response.text?.trim() || '{}';
    return JSON.parse(jsonStr) as ArtifactResponse;
  }
}

export const gemini = new GeminiService();

import React, { useState, useEffect, useRef } from 'react';
import { HashRouter, Routes, Route, useNavigate, useParams } from 'react-router-dom';
import { Session, Message, InputMode, ArtifactType } from './types';
import { gemini } from './services/geminiService';
import { CaptureButtons } from './components/CaptureButtons';
import { IdeaCard } from './components/IdeaCard';

const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;

const Home: React.FC = () => {
  const [sessions, setSessions] = useState<Session[]>(() => {
    const saved = localStorage.getItem('mindsparks_sessions');
    return saved ? JSON.parse(saved) : [];
  });
  const [isRecording, setIsRecording] = useState(false);
  const mediaRecorder = useRef<MediaRecorder | null>(null);
  const recognition = useRef<any>(null);
  const audioChunks = useRef<Blob[]>([]);
  const navigate = useNavigate();

  const startNewSession = async (mode: InputMode, initialContent: string, mediaUrl?: string) => {
    const newSession: Session = {
      id: Date.now().toString(),
      timestamp: Date.now(),
      initialSpark: initialContent,
      type: mode,
      status: 'interviewing',
      messages: [{ role: 'user', text: initialContent, mediaUrl }],
      mediaUrl: mediaUrl
    };
    const updated = [newSession, ...sessions];
    setSessions(updated);
    localStorage.setItem('mindsparks_sessions', JSON.stringify(updated));
    navigate(`/interview/${newSession.id}`);
  };

  const startRecording = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      mediaRecorder.current = new MediaRecorder(stream);
      audioChunks.current = [];

      let transcript = '';
      if (SpeechRecognition) {
        recognition.current = new SpeechRecognition();
        recognition.current.lang = 'zh-CN';
        recognition.current.continuous = true;
        recognition.current.interimResults = true;
        recognition.current.onresult = (event: any) => {
          transcript = Array.from(event.results)
            .map((result: any) => result[0])
            .map((result: any) => result.transcript)
            .join('');
        };
        recognition.current.start();
      }

      mediaRecorder.current.ondataavailable = (event) => audioChunks.current.push(event.data);
      mediaRecorder.current.onstop = () => {
        const audioBlob = new Blob(audioChunks.current, { type: 'audio/webm' });
        const mediaUrl = URL.createObjectURL(audioBlob);
        startNewSession('voice', transcript || "（语音备忘录）", mediaUrl);
      };

      mediaRecorder.current.start();
      setIsRecording(true);
    } catch (err) {
      console.error("无法访问麦克风", err);
    }
  };

  const stopRecording = () => {
    if (mediaRecorder.current) mediaRecorder.current.stop();
    if (recognition.current) recognition.current.stop();
    setIsRecording(false);
  };

  const handleCapture = (mode: InputMode) => {
    if (mode === 'text') {
       const text = prompt("新建一个想法备忘：");
       if (text) startNewSession('text', text);
    } else if (mode === 'photo') {
      const input = document.createElement('input');
      input.type = 'file';
      input.accept = 'image/*';
      input.onchange = (e: any) => {
        const file = e.target.files[0];
        if (file) startNewSession('photo', "上传了图片灵感", URL.createObjectURL(file));
      };
      input.click();
    } else if (mode === 'voice') {
      if (isRecording) stopRecording();
      else startRecording();
    }
  };

  return (
    <div className="max-w-5xl mx-auto px-6 py-16 min-h-screen">
      <header className="mb-16 border-b border-slate-800 pb-8 flex justify-between items-end">
        <div>
          <h1 className="text-5xl font-serif font-black tracking-tight text-white mb-2 italic">缪斯灵感集</h1>
          <p className="text-slate-400 font-medium font-serif italic">你的智能想法备忘录，每一次记录都是深度的开始。</p>
        </div>
        <div className="hidden md:block text-slate-600 text-sm font-mono">
          {sessions.length} 个想法存入馆藏
        </div>
      </header>

      {sessions.length === 0 ? (
        <div className="py-24 text-center border-2 border-dashed border-slate-800 rounded-3xl">
           <i className="fa-solid fa-lightbulb text-4xl text-slate-700 mb-4"></i>
           <p className="text-slate-500">尚无灵感存入。点击下方按钮，开启你的第一场思维碰撞。</p>
        </div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
          {sessions.map(s => (
            <IdeaCard 
              key={s.id} 
              session={s} 
              onClick={(id) => navigate(s.status === 'completed' ? `/artifact/${id}` : `/interview/${id}`)} 
            />
          ))}
        </div>
      )}

      <CaptureButtons onModeSelect={handleCapture} isRecording={isRecording} />
    </div>
  );
};

const InterviewStudio: React.FC = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const [session, setSession] = useState<Session | null>(null);
  const [inputText, setInputText] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [isRecording, setIsRecording] = useState(false);

  const chatRef = useRef<any>(null);
  const scrollRef = useRef<HTMLDivElement>(null);
  const mediaRecorder = useRef<MediaRecorder | null>(null);
  const recognition = useRef<any>(null);
  const audioChunks = useRef<Blob[]>([]);

  useEffect(() => {
    const saved = localStorage.getItem('mindsparks_sessions');
    if (saved) {
      const data: Session[] = JSON.parse(saved);
      const found = data.find(s => s.id === id);
      if (found) {
        setSession(found);
        if (!chatRef.current) {
          // 初始化聊天：加载所有历史消息（除了最末一条如果是刚加的还没回复的消息）
          chatRef.current = gemini.createInterviewChat(found.messages.filter(m => m.role === 'model' || found.messages.indexOf(m) < found.messages.length - 1));

          // 如果是全新的对话（只有一条用户消息），则自动触发 AI
          if (found.messages.length === 1 && found.messages[0].role === 'user') {
            sendToAI(found.initialSpark);
          } else if (found.status === 'interviewing' && found.messages[found.messages.length - 1].role === 'user') {
            // 如果是从成果页点击“继续探讨”回来的，用户可能还没说新话，或者最后一条是用户新说的
            sendToAI(found.messages[found.messages.length - 1].text);
          }
        }
      }
    }
  }, [id]);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [session?.messages, isTyping]);

  const sendToAI = async (text: string) => {
    if (!chatRef.current) return;
    setIsTyping(true);
    try {
      const result = await chatRef.current.sendMessage({ message: text });
      const aiResponse = result.text;

      setSession(prev => {
        if (!prev) return null;
        // 检查最后一条消息是否已经是该回复（防止重复）
        if (prev.messages[prev.messages.length - 1].text === aiResponse) return prev;

        const newMessages: Message[] = [...prev.messages, { role: 'model', text: aiResponse }];
        const updated = { ...prev, messages: newMessages };
        updateStorage(updated);
        return updated;
      });
    } catch (error) {
      console.error("AI 响应出错", error);
    } finally {
      setIsTyping(false);
    }
  };

  const handleSend = (text: string, mediaUrl?: string) => {
    if (!text.trim() || !session) return;
    const userMsg: Message = { role: 'user', text, mediaUrl };
    const updatedMessages = [...session.messages, userMsg];
    setSession({ ...session, messages: updatedMessages });
    setInputText('');
    sendToAI(text);
  };

  const startVoiceInput = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      mediaRecorder.current = new MediaRecorder(stream);
      audioChunks.current = [];
      let transcript = '';
      if (SpeechRecognition) {
        recognition.current = new SpeechRecognition();
        recognition.current.lang = 'zh-CN';
        recognition.current.continuous = true;
        recognition.current.interimResults = true;
        recognition.current.onresult = (event: any) => {
          transcript = Array.from(event.results)
            .map((result: any) => result[0])
            .map((result: any) => result.transcript)
            .join('');
          setInputText(transcript);
        };
        recognition.current.start();
      }
      mediaRecorder.current.ondataavailable = (event) => audioChunks.current.push(event.data);
      mediaRecorder.current.onstop = () => {
        const audioBlob = new Blob(audioChunks.current, { type: 'audio/webm' });
        const mediaUrl = URL.createObjectURL(audioBlob);
        if (transcript) handleSend(transcript, mediaUrl);
      };
      mediaRecorder.current.start();
      setIsRecording(true);
    } catch (err) { console.error(err); }
  };

  const stopVoiceInput = () => {
    if (mediaRecorder.current) mediaRecorder.current.stop();
    if (recognition.current) recognition.current.stop();
    setIsRecording(false);
  };

  const updateStorage = (updated: Session) => {
    const saved = localStorage.getItem('mindsparks_sessions');
    if (saved) {
      const data: Session[] = JSON.parse(saved);
      const idx = data.findIndex(s => s.id === updated.id);
      if (idx > -1) {
        data[idx] = updated;
        localStorage.setItem('mindsparks_sessions', JSON.stringify(data));
      }
    }
  };

  const finishInterview = async (type: ArtifactType) => {
    if (!session) return;
    setSession({ ...session, status: 'synthesizing' });
    try {
      const artifact = await gemini.synthesizeArtifact(session.messages, type);
      const updated: Session = {
        ...session,
        status: 'completed',
        finalArtifact: { ...artifact, type }
      };
      setSession(updated);
      updateStorage(updated);
      navigate(`/artifact/${session.id}`);
    } catch (e) {
      console.error(e);
      alert("生成失败，请稍后重试。");
      setSession({ ...session, status: 'interviewing' });
    }
  };

  if (!session) return null;

  const typeLabels: Record<ArtifactType, string> = {
    'Article': '深度文章',
    'Interview': '精彩访谈',
    'Action Plan': '执行方案'
  };

  return (
    <div className="flex h-screen bg-slate-950 text-slate-100 overflow-hidden">
      {/* 侧边栏 */}
      <div className="w-1/4 border-r border-slate-800 p-8 hidden lg:flex flex-col overflow-y-auto">
        <button onClick={() => navigate('/')} className="mb-12 text-slate-500 hover:text-white flex items-center gap-2 transition-colors">
           <i className="fa-solid fa-arrow-left"></i> 返回灵感库
        </button>
        <div className="flex-1">
          <h2 className="text-xs font-bold text-slate-500 uppercase tracking-widest mb-6">备忘记录</h2>
          <div className="p-4 bg-slate-900 rounded-2xl border border-slate-800 italic text-slate-400 text-sm mb-8 leading-relaxed">
            "{session.initialSpark}"
          </div>

          <h2 className="text-xs font-bold text-slate-500 uppercase tracking-widest mb-6">本次迭代目标</h2>
          <div className="space-y-3">
            {(['Article', 'Interview', 'Action Plan'] as ArtifactType[]).map(type => (
              <button 
                key={type}
                onClick={() => finishInterview(type)}
                disabled={session.status === 'synthesizing'}
                className="w-full text-left px-4 py-3 rounded-xl border border-slate-800 hover:bg-indigo-600/10 hover:border-indigo-500 transition-all text-sm font-medium disabled:opacity-50"
              >
                生成新版 {typeLabels[type]}
              </button>
            ))}
          </div>
        </div>
        <div className="mt-8 pt-8 border-t border-slate-800 text-[10px] text-slate-600 uppercase tracking-widest">
          灵感进化中...
        </div>
      </div>

      {/* 聊天主区域 */}
      <div className="flex-1 flex flex-col relative">
        <div ref={scrollRef} className="flex-1 overflow-y-auto p-8 space-y-8 pb-40">
          {session.messages.map((m, i) => (
            <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
              <div className={`max-w-[80%] p-6 rounded-3xl ${m.role === 'user' ? 'bg-indigo-600 text-white rounded-tr-none shadow-xl shadow-indigo-900/20' : 'bg-slate-900/80 backdrop-blur border border-slate-800 rounded-tl-none font-serif text-lg leading-relaxed text-slate-100'}`}>
