const CACHE_NAME = 'muse-v1';
const ASSETS = [
  '/',
  '/index.html',
  '/manifest.json'
];

self.addEventListener('install', (event) => {
  event.waitUntil(
    caches.open(CACHE_NAME).then((cache) => {
      return cache.addAll(ASSETS);
    })
  );
});

self.addEventListener('fetch', (event) => {
  event.respondWith(
    caches.match(event.request).then((response) => {
      return response || fetch(event.request);
    })
  );
});

import React, { useState, useEffect, useRef } from 'react';
import { HashRouter, Routes, Route, useNavigate, useParams } from 'react-router-dom';
import { Session, Message, InputMode, ArtifactType } from './types';
import { gemini } from './services/geminiService';
import { CaptureButtons } from './components/CaptureButtons';
import { IdeaCard } from './components/IdeaCard';

const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;

const Home: React.FC = () => {
  const [sessions, setSessions] = useState<Session[]>(() => {
    const saved = localStorage.getItem('mindsparks_sessions');
    return saved ? JSON.parse(saved) : [];
  });
  const [isRecording, setIsRecording] = useState(false);
  const [showManage, setShowManage] = useState(false);
  const [installPrompt, setInstallPrompt] = useState<any>(null);

  const mediaRecorder = useRef<MediaRecorder | null>(null);
  const recognition = useRef<any>(null);
  const audioChunks = useRef<Blob[]>([]);
  const navigate = useNavigate();

  useEffect(() => {
    window.addEventListener('beforeinstallprompt', (e) => {
      e.preventDefault();
      setInstallPrompt(e);
    });
  }, []);

  const handleInstall = async () => {
    if (!installPrompt) return;
    installPrompt.prompt();
    const { outcome } = await installPrompt.userChoice;
    if (outcome === 'accepted') setInstallPrompt(null);
  };

  const startNewSession = async (mode: InputMode, initialContent: string, mediaUrl?: string) => {
    const newSession: Session = {
      id: Date.now().toString(),
      timestamp: Date.now(),
      initialSpark: initialContent,
      type: mode,
      status: 'interviewing',
      messages: [{ role: 'user', text: initialContent, mediaUrl }],
      mediaUrl: mediaUrl
    };
    const updated = [newSession, ...sessions];
    setSessions(updated);
    localStorage.setItem('mindsparks_sessions', JSON.stringify(updated));
    navigate(`/interview/${newSession.id}`);
  };

  const exportData = () => {
    const dataStr = JSON.stringify(sessions, null, 2);
    const dataUri = 'data:application/json;charset=utf-8,' + encodeURIComponent(dataStr);
    const link = document.createElement('a');
    link.href = dataUri;
    link.download = `muse_backup_${new Date().toISOString().slice(0,10)}.json`;
    link.click();
  };

  const importData = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const imported = JSON.parse(event.target?.result as string);
        if (Array.isArray(imported)) {
          const merged = [...imported, ...sessions].filter((v, i, a) => a.findIndex(t => t.id === v.id) === i);
          setSessions(merged);
          localStorage.setItem('mindsparks_sessions', JSON.stringify(merged));
          alert("导入成功！");
          setShowManage(false);
        }
      } catch (err) { alert("导入失败"); }
    };
    reader.readAsText(file);
  };

  const startRecording = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      mediaRecorder.current = new MediaRecorder(stream);
      audioChunks.current = [];
      let transcript = '';
      if (SpeechRecognition) {
        recognition.current = new SpeechRecognition();
        recognition.current.lang = 'zh-CN';
        recognition.current.continuous = true;
        recognition.current.onresult = (e: any) => {
          transcript = Array.from(e.results).map((r: any) => r[0].transcript).join('');
        };
        recognition.current.start();
      }
      mediaRecorder.current.ondataavailable = (e) => audioChunks.current.push(e.data);
      mediaRecorder.current.onstop = () => {
        const audioBlob = new Blob(audioChunks.current, { type: 'audio/webm' });
        startNewSession('voice', transcript || "语音记录", URL.createObjectURL(audioBlob));
      };
      mediaRecorder.current.start();
      setIsRecording(true);
    } catch (err) { alert("请在手机浏览器设置中开启麦克风权限"); }
  };

  const stopRecording = () => {
    mediaRecorder.current?.stop();
    recognition.current?.stop();
    setIsRecording(false);
  };

  const handleCapture = (mode: InputMode) => {
    if (mode === 'text') {
       const text = prompt("现在的灵感是？");
       if (text) startNewSession('text', text);
    } else if (mode === 'photo') {
      const input = document.createElement('input');
      input.type = 'file';
      input.accept = 'image/*';
      input.onchange = (e: any) => {
        const file = e.target.files[0];
        if (file) startNewSession('photo', "图片备忘", URL.createObjectURL(file));
      };
      input.click();
    } else if (mode === 'voice') {
      if (isRecording) stopRecording();
      else startRecording();
    }
  };

  return (
    <div className="max-w-5xl mx-auto px-6 py-8 md:py-16 min-h-screen flex flex-col">
      <header className="mb-8 md:mb-12 border-b border-slate-800 pb-8 flex justify-between items-center">
        <div>
          <h1 className="text-3xl md:text-5xl font-serif font-black tracking-tight text-white mb-2 italic">缪斯灵感</h1>
          <p className="text-slate-400 font-serif italic text-xs md:text-base">在安卓上，点击右上角“添加到主屏幕”以获得完整体验。</p>
        </div>
        <div className="flex gap-2">
          {installPrompt && (
            <button 
              onClick={handleInstall}
              className="p-3 rounded-full bg-indigo-600 text-white animate-bounce shadow-lg shadow-indigo-500/50"
              title="安装到手机"
            >
              <i className="fa-solid fa-mobile-screen-button"></i>
            </button>
          )}
          <button 
            onClick={() => setShowManage(!showManage)}
            className="p-3 rounded-full bg-slate-900 border border-slate-800 text-slate-400"
          >
            <i className="fa-solid fa-gear"></i>
          </button>
        </div>
      </header>

      {showManage && (
        <div className="mb-8 p-6 glass-morphism rounded-3xl animate-in fade-in duration-300">
          <h2 className="text-xs font-bold text-indigo-400 uppercase tracking-widest mb-4">数据管理</h2>
          <div className="flex flex-col sm:flex-row gap-3">
            <button onClick={exportData} className="px-5 py-3 bg-indigo-600 rounded-xl text-xs font-bold flex items-center justify-center gap-2">
              <i className="fa-solid fa-download"></i> 导出备份
            </button>
            <label className="px-5 py-3 bg-slate-800 rounded-xl text-xs font-bold flex items-center justify-center gap-2 cursor-pointer">
              <i className="fa-solid fa-upload"></i> 导入备份
              <input type="file" accept=".json" onChange={importData} className="hidden" />
            </label>
            <button onClick={() => { if(confirm("清空？")) { localStorage.clear(); window.location.reload(); } }} className="px-5 py-3 bg-red-900/20 text-red-500 border border-red-900/30 rounded-xl text-xs font-bold">
              清空数据
            </button>
          </div>
        </div>
      )}

      {sessions.length === 0 ? (
        <div className="flex-1 flex flex-col items-center justify-center py-20 text-center">
           <div className="w-16 h-16 bg-slate-900 rounded-full flex items-center justify-center mb-6">
             <i className="fa-solid fa-plus text-slate-700 text-2xl"></i>
           </div>
           <p className="text-slate-500 font-serif italic">开始捕获你的第一个灵感火花...</p>
        </div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {sessions.map(s => (
            <IdeaCard 
              key={s.id} 
              session={s} 
              onClick={(id) => navigate(s.status === 'completed' ? `/artifact/${id}` : `/interview/${id}`)} 
            />
          ))}
        </div>
      )}

      <CaptureButtons onModeSelect={handleCapture} isRecording={isRecording} />

      <footer className="mt-auto pt-16 pb-8 text-center text-slate-700 text-[9px] uppercase tracking-widest">
        Muse • Android Optimized • v1.0.2
      </footer>
    </div>
  );
};

const InterviewStudio: React.FC = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const [session, setSession] = useState<Session | null>(null);
  const [inputText, setInputText] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [isRecording, setIsRecording] = useState(false);

  const chatRef = useRef<any>(null);
  const scrollRef = useRef<HTMLDivElement>(null);
  const mediaRecorder = useRef<MediaRecorder | null>(null);
  const recognition = useRef<any>(null);
  const audioChunks = useRef<Blob[]>([]);

  useEffect(() => {
    const saved = localStorage.getItem('mindsparks_sessions');
    if (saved) {
      const data: Session[] = JSON.parse(saved);
      const found = data.find(s => s.id === id);
      if (found) {
        setSession(found);
        if (!chatRef.current) {
          chatRef.current = gemini.createInterviewChat(found.messages.filter(m => m.role === 'model' || found.messages.indexOf(m) < found.messages.length - 1));
          if (found.messages.length === 1 && found.messages[0].role === 'user') {
            sendToAI(found.initialSpark);
          } else if (found.status === 'interviewing' && found.messages[found.messages.length - 1].role === 'user') {
            sendToAI(found.messages[found.messages.length - 1].text);
          }
        }
      }
    }
  }, [id]);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [session?.messages, isTyping]);

  const sendToAI = async (text: string) => {
    if (!chatRef.current) return;
    setIsTyping(true);
    try {
      const result = await chatRef.current.sendMessage({ message: text });
      const aiResponse = result.text;
      setSession(prev => {
        if (!prev) return null;
        if (prev.messages[prev.messages.length - 1].text === aiResponse) return prev;
        const newMessages: Message[] = [...prev.messages, { role: 'model', text: aiResponse }];
        const updated = { ...prev, messages: newMessages };
        updateStorage(updated);
        return updated;
      });
    } catch (e) { console.error(e); } finally { setIsTyping(false); }
  };

  const handleSend = (text: string, mediaUrl?: string) => {
    if (!text.trim() || !session) return;
    const userMsg: Message = { role: 'user', text, mediaUrl };
    const updatedMessages = [...session.messages, userMsg];
    setSession({ ...session, messages: updatedMessages });
    setInputText('');
    sendToAI(text);
  };

  const startVoiceInput = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      mediaRecorder.current = new MediaRecorder(stream);
      audioChunks.current = [];
      let transcript = '';
      if (SpeechRecognition) {
        recognition.current = new SpeechRecognition();
        recognition.current.lang = 'zh-CN';
        recognition.current.continuous = true;
        recognition.current.onresult = (e: any) => {
          transcript = Array.from(e.results).map((r: any) => r[0].transcript).join('');
          setInputText(transcript);
        };
        recognition.current.start();
      }
      mediaRecorder.current.ondataavailable = (e) => audioChunks.current.push(e.data);
      mediaRecorder.current.onstop = () => {
        const audioBlob = new Blob(audioChunks.current, { type: 'audio/webm' });
        if (transcript) handleSend(transcript, URL.createObjectURL(audioBlob));
      };
      mediaRecorder.current.start();
      setIsRecording(true);
    } catch (err) { alert("麦克风启动失败"); }
  };

  const stopVoiceInput = () => {
    mediaRecorder.current?.stop();
    recognition.current?.stop();
    setIsRecording(false);
  };

  const updateStorage = (updated: Session) => {
    const saved = localStorage.getItem('mindsparks_sessions');
    if (saved) {
      const data: Session[] = JSON.parse(saved);
      const idx = data.findIndex(s => s.id === updated.id);
      if (idx > -1) {
        data[idx] = updated;
        localStorage.setItem('mindsparks_sessions', JSON.stringify(data));
      }
    }
  };

  const finishInterview = async (type: ArtifactType) => {
    if (!session) return;
    setSession({ ...session, status: 'synthesizing' });
    try {
      const artifact = await gemini.synthesizeArtifact(session.messages, type);
      const updated: Session = { ...session, status: 'completed', finalArtifact: { ...artifact, type } };
      setSession(updated);
      updateStorage(updated);
      navigate(`/artifact/${session.id}`);
    } catch (e) {
      alert("生成失败");
      setSession({ ...session, status: 'interviewing' });
    }
  };

  if (!session) return null;

  const typeLabels: Record<ArtifactType, string> = {
    'Article': '深度文章',
    'Interview': '精彩访谈',
    'Action Plan': '执行方案'
  };

  return (
    <div className="flex h-screen bg-slate-950 text-slate-100 overflow-hidden flex-col md:flex-row">
      {/* 顶部简易导航 (移动端) */}
      <div className="md:hidden flex items-center justify-between p-4 border-b border-slate-800">
        <button onClick={() => navigate('/')} className="text-slate-400">
          <i className="fa-solid fa-chevron-left"></i>
        </button>
        <span className="text-[10px] font-bold uppercase tracking-widest text-indigo-400">缪斯正在访谈</span>
        <div className="w-4"></div>
      </div>

      {/* 侧边栏 */}
      <div className="w-full md:w-1/4 border-r border-slate-800 p-4 md:p-8 flex flex-col overflow-y-auto max-h-[30vh] md:max-h-full">
        <button onClick={() => navigate('/')} className="hidden md:flex mb-12 text-slate-500 hover:text-white items-center gap-2 transition-colors text-sm">
           <i className="fa-solid fa-arrow-left"></i> 返回馆藏
        </button>
        <div className="flex-1">
          <h2 className="text-[10px] font-bold text-slate-500 uppercase tracking-widest mb-4">访谈火花</h2>
          <div className="p-3 bg-slate-900/50 rounded-xl border border-slate-800 italic text-slate-400 text-xs mb-4 leading-relaxed">
            "{session.initialSpark}"
          </div>

          <div className="grid grid-cols-3 md:grid-cols-1 gap-2">
            {(['Article', 'Interview', 'Action Plan'] as ArtifactType[]).map(type => (
              <button 
                key={type}
                onClick={() => finishInterview(type)}
                disabled={session.status === 'synthesizing'}
                className="text-center md:text-left px-2 py-3 rounded-xl border border-slate-800 bg-slate-900 hover:border-indigo-500 transition-all text-[10px] md:text-sm font-medium"
              >
                生成{typeLabels[type]}
              </button>
            ))}
          </div>
        </div>
      </div>

      {/* 聊天主区域 */}
      <div className="flex-1 flex flex-col relative">
        <div ref={scrollRef} className="flex-1 overflow-y-auto p-4 md:p-8 space-y-6 pb-40">
          {session.messages.map((m, i) => (
            <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
              <div className={`max-w-[85%] p-4 md:p-6 rounded-2xl md:rounded-3xl ${m.role === 'user' ? 'bg-indigo-600 text-white rounded-tr-none' : 'bg-slate-900/90 backdrop-blur border border-slate-800 rounded-tl-none font-serif text-base md:text-lg leading-relaxed'}`}>
                {m.text}
                {m.mediaUrl && (
                  <div className="mt-3 pt-3 border-t border-white/10">
                    <audio src={m.mediaUrl} controls className="h-8 w-full brightness-0 invert opacity-40" />
                  </div>
                )}
              </div>
            </div>
          ))}
          {isTyping && (
            <div className="flex justify-start">
              <div className="bg-slate-900/50 p-3 rounded-xl animate-pulse text-[10px] text-indigo-400 font-bold uppercase tracking-widest">
                缪斯正在构思问询...
              </div>
            </div>
          )}
        </div>

        <div className="absolute bottom-0 left-0 right-0 p-4 md:p-8 bg-gradient-to-t from-slate-950 via-slate-950 to-transparent">
          <div className="max-w-3xl mx-auto flex gap-3 items-center">
            <button 
              onClick={isRecording ? stopVoiceInput : startVoiceInput}
              className={`p-4 rounded-full shadow-2xl transition-all ${isRecording ? 'bg-red-500' : 'bg-slate-800'}`}
            >
              <i className={`fa-solid ${isRecording ? 'fa-stop' : 'fa-microphone'} text-white`}></i>
            </button>
            <div className="flex-1 relative">
              <input 
                type="text"
                value={inputText}
                onChange={e => setInputText(e.target.value)}
                onKeyDown={e => e.key === 'Enter' && handleSend(inputText)}
                placeholder={isRecording ? "请畅所欲言..." : "继续交流思考..."}
                className="w-full bg-slate-900/90 border border-slate-700 rounded-full px-6 py-4 pr-14 focus:outline-none focus:border-indigo-500 transition-all text-sm md:text-base"
              />
              <button 
                onClick={() => handleSend(inputText)}
                className="absolute right-2 top-1/2 -translate-y-1/2 p-2.5 bg-indigo-600 rounded-full"
              >
                <i className="fa-solid fa-arrow-up text-white text-xs"></i>
              </button>
            </div>
          </div>
        </div>
      </div>

